package com.socialblog.comment.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;
@Entity @Table(name="comments")public class Comment{@Id private UUID id;@Column(name="article_id",nullable=false)private UUID articleId;@Column(name="author_id",nullable=false)private UUID authorId;@Column(name="parent_id")private UUID parentId;@Column(nullable=false,length=2000)private String content;@Enumerated(EnumType.STRING)@Column(nullable=false)private Status status;@Column(name="created_at",nullable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected Comment(){}public Comment(UUID article,UUID author,UUID parent,String content){id=UUID.randomUUID();articleId=article;authorId=author;parentId=parent;status=Status.ACTIVE;createdAt=Instant.now();update(content);}public void update(String value){if(status==Status.DELETED)throw new IllegalStateException();content=value.trim();updatedAt=Instant.now();}public void delete(){status=Status.DELETED;content="";updatedAt=Instant.now();}public UUID getId(){return id;}public UUID getArticleId(){return articleId;}public UUID getAuthorId(){return authorId;}public UUID getParentId(){return parentId;}public String getContent(){return content;}public Status getStatus(){return status;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}public enum Status{ACTIVE,DELETED}}
